/*
 * This class fetches and exposes the view over Vimium's settings data, which is stored in
 * chrome.storage. It merges the user's customizations into the default setting values.
 * It dispatches the "change" event when the settings have been changed.
 */
const Settings = {
  _settings: null,
  _chromeStorageListenerInstalled: false,

  defaultOptions,
  newTabDestinations,
  vimiumNewTabPageUrl,

  async onLoaded() {
    if (!this.isLoaded()) {
      await this.load();
    }
  },

  async chromeStorageOnChanged(_changes, area) {
    // We store data with keys [settings-v1, ...] into the local storage. Only broadcast an event if
    // the object stored with the settings key has changed.
    // We only store settings in the sync area, so storage.sync changes must be settings changes.
    if (area == "sync") {
      await this.load();
      this.dispatchEvent("change");
    }
  },

  async load() {
    // NOTE(philc): If we change the schema of the settings object in a backwards-incompatible way,
    // then we can fetch the whole storage object here and migrate any old settings the user has to
    // the new schema.
    if (!this._chromeStorageListenerInstalled) {
      this._chromeStorageListenerInstalled = true;
      chrome.storage.onChanged.addListener((changes, area) =>
        this.chromeStorageOnChanged(changes, area)
      );
    }

    let result = await chrome.storage.sync.get(null); // Get every key.
    result = this.migrateSettingsIfNecessary(result);
    result["settingsVersion"] = Utils.getCurrentVersion();
    this._settings = Object.assign(globalThis.structuredClone(defaultOptions), result);
  },

  isLoaded() {
    return this._settings != null;
  },

  get(key) {
    if (!this.isLoaded()) {
      throw new Error(`Getting the setting ${key} before settings have been loaded.`);
    }
    return globalThis.structuredClone(this._settings[key]);
  },

  async set(key, value) {
    if (!this.isLoaded()) {
      throw new Error(`Writing the setting ${key} before settings have been loaded.`);
    }
    this._settings[key] = value;
    await this.setSettings(this._settings);
  },

  getSettings() {
    return globalThis.structuredClone(this._settings);
  },

  migratePre2_0(settings) {
    // Prior to Vimium version 2.0.0:
    // - In chrome.storages.sync, the value of each setting was encoded as a JSON string using
    //   JSON.stringify. This was probably an artifact of originally using localStorage, but is no
    //   longer necessary now that chrome.storage exists and can store objects. Note that when
    //   exporting a backup of settings on the options page, the values were not encoded as JSON
    //   strings.
    // - We only stored the settingsVersion key in the JSON payload when a user exported a backup of
    //   their settings. It wasn't set when writing the settings to chrome.storage.sync.

    // NOTE(philc): We want to migrate settings which have JSON-encoded values. Based on the notes
    // above, that should mean we only need to migrate if the settings object is missing a
    // "settingsVersion" key.
    const shouldMigrate = settings["settingsVersion"] == null;
    if (!shouldMigrate) return settings;

    // Migration for v2.0.0: decode all values so that they're not JSON string encoded.
    const newSettings = {};
    for (const [k, v] of Object.entries(settings)) {
      // Most pre-2.0 settings were strings, but the global marks were stored as native values. See
      // #4323. So check the setting value's type before migrating.
      if (typeof v === "string") {
        newSettings[k] = JSON.parse(v);
      } else {
        newSettings[k] = v;
      }
    }
    // This key is no longer stored in our settings, but rather chrome.storage.session.
    delete newSettings.passNextKeyKeys;
    return newSettings;
  },

  migratePre2_4(settings) {
    const version = settings["settingsVersion"];
    // In 2.4 we added some new settings which control the URL that new tabs are opened in.
    const shouldMigrate = version && (Utils.compareVersions(version, "2.4") < 0);
    if (!shouldMigrate) return settings;
    const previousDefaultNewTabUrl = "about:newtab";
    if (!settings.newTabUrl || settings.newTabUrl == previousDefaultNewTabUrl) {
      // newTabUrl was absent (user never changed from the default, so it was pruned from storage)
      // or was explicitly set to the browser's default new tab URL.
      settings.newTabDestination = newTabDestinations.browserNewTabPage;
    } else if (settings.newTabUrl == "pages/blank.html") {
      // This was meant to be used as a blank page, but we no longer include this page in Vimium.
      // We use "vimium.github.io/new-tab/" instead.
      settings.newTabDestination = newTabDestinations.vimiumNewTabPage;
    } else if (settings.newTabUrl) {
      // It's some other custom URL the user has set.
      settings.newTabDestination = newTabDestinations.customUrl;
      settings.newTabCustomUrl = settings.newTabUrl;
    }
    delete settings.newTabUrl;
    return settings;
  },

  migratePre2_4_1(settings) {
    // In migratePre2_4, there was a bug: pre-2.4 users who had never changed their newTabUrl (which
    // defaulted to "about:newtab") were incorrectly given newTabDestination = "vimiumNewTabPage".
    // Fix this by setting newTabDestination = "browserNewTabPage" for any 2.4.0 user who hasn't set
    // their newTabDestination to something other than "vimiumNewTabPage" (the default value).
    const version = settings["settingsVersion"];
    // Only run this for users that went through the buggy 2.4.0 migration (version >= "2.4" but <
    // "2.4.1"). Users upgrading directly from pre-2.4 are handled correctly by the (since
    // corrected) migratePre2_4 and should not have this fixup applied.
    const shouldMigrate = version &&
      (Utils.compareVersions(version, "2.4") >= 0) &&
      (Utils.compareVersions(version, "2.4.1") < 0);
    if (!shouldMigrate) return settings;
    const dest = settings.newTabDestination;
    if (!dest || dest == newTabDestinations.vimiumNewTabPage) {
      settings.newTabDestination = newTabDestinations.browserNewTabPage;
    }
    return settings;
  },

  // Returns a settings object and performs any migrations required if the settings object is from
  // an older version of Vimium.
  migrateSettingsIfNecessary(settings) {
    settings = this.migratePre2_0(settings);
    settings = this.migratePre2_4(settings);
    settings = this.migratePre2_4_1(settings);
    return settings;
  },

  async setSettings(settings) {
    settings = this.migrateSettingsIfNecessary(settings);
    settings["settingsVersion"] = Utils.getCurrentVersion();
    const result = this.pruneOutDefaultValues(settings);
    // If, after pruning, some keys were removed because their values are now equal to the default
    // values, then explicitly clear those from storage. Otherwise they will remain.
    // NOTE(philc): This kind of sharp edge is a reason to switch to storing the settings object as
    // one big object, rather than as top-level keys in chrome.storage. The tradeoff is that each
    // value in chrome-storage has a maximum size.
    const resultKeys = Object.keys(result);
    const removedKeys = Object.keys(settings).filter((key) => !resultKeys.includes(key));
    await chrome.storage.sync.remove(removedKeys);
    await chrome.storage.sync.set(result);
    await this.load();
  },

  // Returns a new object, removing the keys from `settings` which are equal to the default values
  // for those keys.
  pruneOutDefaultValues(settings) {
    const clonedSettings = globalThis.structuredClone(settings);
    for (const [k, v] of Object.entries(settings)) {
      if (JSON.stringify(v) == JSON.stringify(defaultOptions[k])) {
        delete clonedSettings[k];
      }
    }
    return clonedSettings;
  },

  // Used only by tests.
  async clear() {
    this._settings = null;
    await chrome.storage.sync.clear();
  },
};

Object.assign(Settings, EventDispatcher);

globalThis.Settings = Settings;

/* ====== lib/url_utils.js ====== */
const UrlUtils = {
  chromeNewTabUrl: "about:newtab",

  // A set of top-level domains, e.g. ["com"] recognized by https://www.iana.org/domains/root/db
  tlds: null,

  // Other hard-coded TLDs that we want to recognize as URLs.
  otherTlds: [
    // Multicast DNS uses 'local' to resolve hostnames to IP addresses within small networks.
    "local",
    // A pseudo-domain used by TOR browsers.
    "onion",
  ],

  async init() {
    if (this.tlds != null) return;
    // Load the tlds.txt file relative to this module. This is required for this URL
    // to be valid both when running tests, and in the browser.
    const inUnitTests = globalThis.Deno;
    const path = "./resources/tlds.txt";
    let text;
    // Deno and the browser require different URLs to resolve tlds.txt. If we change
    // url_utils.js to be imported as a module, then can both use an import path
    // that's relative to the module:
    // const tldsFileUrl = new URL("resources/tlds.txt", new URL(import.meta.url));
    if (inUnitTests) {
      text = await Deno.readTextFile(path);
    } else {
      const response = await fetch(chrome.runtime.getURL(path));
      text = await response.text();
    }
    this.tlds = new Set(text.split("\n"));
  },

  // Tries to detect if :str is a valid URL.
  async isUrl(str) {
    if (this.tlds == null) {
      await this.init();
    }

    // Must not contain spaces
    if (str.includes(" ")) return false;

    // Starts with a scheme: URL
    if (this.urlHasProtocol(str)) return true;

    // More or less RFC compliant URL host part parsing. This should be sufficient for our needs
    const urlRegex = new RegExp(
      "^(?:([^:]+)(?::([^:]+))?@)?" + // user:password (optional) => \1, \2
        "([^:]+|\\[[^\\]]+\\])" + // host name (IPv6 addresses in square brackets allowed) => \3
        "(?::(\\d+))?$", // port number (optional) => \4
    );

    const specialHostNames = ["localhost"];

    // Try to parse the URL into its meaningful parts. If matching fails we're pretty sure that we
    // don't have some kind of URL here.
    // TODO(philc): Can't we use URL() here? This code might've been written before the URL class
    // existed.
    const match = urlRegex.exec((str.split("/"))[0]);
    if (!match) return false;
    const hostName = match[3];

    // Allow known special host names
    if (specialHostNames.includes(hostName)) return true;

    // Allow IPv6 addresses (need to be wrapped in brackets as required by RFC). It is sufficient to
    // check for a colon, as the regex wouldn't match colons in the host name unless it's an v6
    // address
    if (hostName.includes(":")) return true;

    // At this point we have to make a decision. As a heuristic, we check if the input has dots in
    // it. If yes, and if the last part could be a TLD, treat it as an URL
    const dottedParts = hostName.split(".");

    if (dottedParts.length > 1) {
      const lastPart = dottedParts.pop();
      if (this.tlds.has(lastPart) || this.otherTlds.includes(lastPart)) {
        return true;
      }
    }

    // Allow IPv4 addresses
    if (/^(\d{1,3}\.){3}\d{1,3}$/.test(hostName)) return true;

    // Fallback: no URL
    return false;
  },

  // Converts string into a full URL if it's not already one. We don't escape characters as the
  // browser will do that for us.
  async convertToUrl(string) {
    string = string.trim();

    // Special-case about:[url], view-source:[url] and the like
    if (this.hasChromeProtocol(string)) {
      return string;
    } else if (this.hasJavascriptProtocol(string)) {
      return string;
    } else if (await this.isUrl(string)) {
      return this.urlHasProtocol(string) ? string : `http://${string}`;
    } else {
      return null;
    }
  },

  _chromePrefixes: ["about:", "view-source:", "extension:", "chrome-extension:", "data:"],
  hasChromeProtocol(url) {
    return this._chromePrefixes.some((prefix) => url.startsWith(prefix));
  },

  hasJavascriptProtocol(url) {
    return url.startsWith("javascript:");
  },

  _urlPrefix: new RegExp("^[a-z][-+.a-z0-9]{2,}://."),
  urlHasProtocol(url) {
    return this._urlPrefix.test(url);
  },

  // Create a search URL from the given :query using the provided search URL.
  createSearchUrl(query, searchUrl) {
    if (!["%s", "%S"].some((token) => searchUrl.indexOf(token) >= 0)) {
      searchUrl += "%s";
    }
    searchUrl = searchUrl.replace(/%S/g, query);

    // Map a search query to its URL encoded form. E.g. "BBC Sport" -> "BBC%20Sport".
    const parts = query.split(/\s+/);
    const encodedQuery = parts.map(encodeURIComponent).join("%20");
    return searchUrl.replace(/%s/g, encodedQuery);
  },
};

globalThis.UrlUtils = UrlUtils;

/* ====== background_scripts/tab_recency.js ====== */
// TabRecency associates an integer with each tab id representing how recently it has been accessed.
// The order of tabs as tracked by TabRecency is used to provide a recency-based ordering in the
// tabs vomnibar.
//
// The values are persisted to chrome.storage.session so that they're not lost when the extension's
// background page is unloaded.
//
// Callers must await TabRecency.init before calling recencyScore or getTabsByRecency.
//
// In theory, the browser's tab.lastAccessed timestamp field should allow us to sort tabs by
// recency, but in practice it does not work across several edge cases. See the comments on #4368.
class TabRecency {
  constructor() {
    this.counter = 1;
    this.tabIdToCounter = {};
    this.loaded = false;
    this.queuedActions = [];
  }

  // Add listeners to chrome.tabs, and load the index from session storage.
  async init() {
    if (this.initPromise) {
      await this.initPromise;
      return;
    }
    let resolveFn;
    this.initPromise = new Promise((resolve, _reject) => {
      resolveFn = resolve;
    });

    chrome.tabs.onActivated.addListener((activeInfo) => {
      this.queueAction("register", activeInfo.tabId);
    });
    chrome.tabs.onRemoved.addListener((tabId) => {
      this.queueAction("deregister", tabId);
    });

    chrome.tabs.onReplaced.addListener((addedTabId, removedTabId) => {
      this.queueAction("deregister", removedTabId);
      this.queueAction("register", addedTabId);
    });

    chrome.windows.onFocusChanged.addListener(async (windowId) => {
      if (windowId == chrome.windows.WINDOW_ID_NONE) return;
      const tabs = await chrome.tabs.query({ windowId, active: true });
      if (tabs[0]) {
        this.queueAction("register", tabs[0].id);
      }
    });

    await this.loadFromStorage();
    while (this.queuedActions.length > 0) {
      const [action, tabId] = this.queuedActions.shift();
      this.handleAction(action, tabId);
    }
    this.loaded = true;
    resolveFn();
  }

  // Loads the index from session storage.
  async loadFromStorage() {
    const tabsPromise = chrome.tabs.query({});
    const storagePromise = chrome.storage.session.get("tabRecency");
    const [tabs, storage] = await Promise.all([tabsPromise, storagePromise]);
    if (storage.tabRecency == null) return;

    let maxCounter = 0;
    for (const counter of Object.values(storage.tabRecency)) {
      if (maxCounter < counter) maxCounter = counter;
    }
    if (this.counter < maxCounter) {
      this.counter = maxCounter;
    }

    this.tabIdToCounter = Object.assign({}, storage.tabRecency);

    // Remove any tab IDs which aren't currently loaded.
    const tabIds = new Set(tabs.map((t) => t.id));
    for (const id in this.tabIdToCounter) {
      if (!tabIds.has(parseInt(id))) {
        delete this.tabIdToCounter[id];
      }
    }
  }

  async saveToStorage() {
    await chrome.storage.session.set({ tabRecency: this.tabIdToCounter });
  }

  // - action: "register" or "unregister".
  queueAction(action, tabId) {
    if (!this.loaded) {
      this.queuedActions.push([action, tabId]);
    } else {
      this.handleAction(action, tabId);
    }
  }

  // - action: "register" or "unregister".
  handleAction(action, tabId) {
    if (action == "register") {
      this.register(tabId);
    } else if (action == "deregister") {
      this.deregister(tabId);
    } else {
      throw new Error(`Unexpected action type: ${action}`);
    }
  }

  register(tabId) {
    this.counter++;
    this.tabIdToCounter[tabId] = this.counter;
    this.saveToStorage();
  }

  deregister(tabId) {
    delete this.tabIdToCounter[tabId];
    this.saveToStorage();
  }

  // Recently-visited tabs get a higher score (except the current tab, which gets a low score).
  recencyScore(tabId) {
    if (!this.loaded) throw new Error("TabRecency hasn't yet been loaded.");
    const tabCounter = this.tabIdToCounter[tabId];
    const isCurrentTab = tabCounter == this.counter;
    if (isCurrentTab) return 0;
    return (tabCounter ?? 1) / this.counter; // tabCounter may be null.
  }

  // Returns a list of tab Ids sorted by recency, most recent tab first.
  getTabsByRecency() {
    if (!this.loaded) throw new Error("TabRecency hasn't yet been loaded.");
    const ids = Object.keys(this.tabIdToCounter);
    ids.sort((a, b) => this.tabIdToCounter[b] - this.tabIdToCounter[a]);
    return ids.map((id) => parseInt(id));
  }
}


// Safari bundle: export symbols to globalThis
globalThis.TabRecency = TabRecency;

/* ====== background_scripts/bg_utils.js ====== */
// We're using browser.runtime to determine the browser name and version for Firefox. That API is
// only available on the background page. We're not using window.navigator because it's unreliable.
// Sometimes browser vendors will provide fake values, like when `privacy.resistFingerprinting` is
// enabled on `about:config` of Firefox.
function isFirefox() {
  // We want this browser check to also cover Firefox variants, like LibreWolf. See #3773.
  // We could also just check browserInfo.name against Firefox and Librewolf.
  return globalThis.browser?.runtime.getURL("").startsWith("moz") ?? false;
}

// Detect Safari. In the background service worker context, Safari provides the global `safari` object.
// We also check the user agent as a fallback.
function isSafari() {
  if (typeof globalThis.safari !== "undefined") return true;
  if (typeof navigator === "undefined" || !navigator.userAgent) return false;
  const ua = navigator.userAgent;
  return ua.includes("Safari") && !ua.includes("Chrome") && !ua.includes("Firefox");
}

async function getFirefoxVersion() {
  return isFirefox() ? (await browser.runtime.getBrowserInfo()).version : null;
}

// TODO(philc): tabRecency imports bg_utils. We should resovle the cycle for the sake of clarity.
const tabRecency = new TabRecency();
tabRecency.init();

// Safari bundle: export symbols to globalThis
globalThis.isFirefox = isFirefox;
globalThis.isSafari = isSafari;
globalThis.getFirefoxVersion = getFirefoxVersion;
globalThis.tabRecency = tabRecency;

